import hashlib

def calculate_file_hash(file_path):
    """
    Calculate the SHA-256 hash of a file.
    
    Args:
        file_path (str): Path to the file for which the hash is calculated.
    
    Returns:
        str: The SHA-256 hash of the file as a hexadecimal string.
    """
    try:
        with open(file_path, 'rb') as f:
            # Read the file in chunks to avoid loading it all into memory
            for chunk in iter(lambda: f.read(4096), b""):
                # Update the hash object with the current chunk
                hashlib.sha256.update(chunk)
        
        # Return the final hash value as a hexadecimal string
        return hashlib.sha256().hexdigest()
    
    except Exception as e:
        print(f"Error calculating file hash: {e}")
        return None

# Example usage:
file_path = 'path_to_your_file.txt'
print(calculate_file_hash(file_path))